import{_ as a,c as t,o as r,a1 as i}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"Interruption de flux: Dépannage 0 Token | Antigravity-Manager","description":"Apprenez le chemin de dépannage des interruptions de flux, 0 Token et signatures invalides dans Antigravity Tools. Confirmez /v1/messages ou appel natif Gemini, comprenez la pré-lecture peek et la nouvelle tentative avec délai, combinez Proxy Monitor et les journaux pour localiser rapidement la cause et déterminer si vous devez faire pivoter les comptes.","frontmatter":{"title":"Interruption de flux: Dépannage 0 Token | Antigravity-Manager","sidebarTitle":"Auto-guérison ou intervention manuelle","subtitle":"Interruption de flux/0 Token/Signature invalide : mécanisme d'auto-guérison et chemin de dépannage","description":"Apprenez le chemin de dépannage des interruptions de flux, 0 Token et signatures invalides dans Antigravity Tools. Confirmez /v1/messages ou appel natif Gemini, comprenez la pré-lecture peek et la nouvelle tentative avec délai, combinez Proxy Monitor et les journaux pour localiser rapidement la cause et déterminer si vous devez faire pivoter les comptes.","tags":["faq","streaming","dépannage","retry"],"prerequisite":["start-getting-started","start-first-run-data","advanced-monitoring","advanced-scheduling"],"order":5},"headers":[],"relativePath":"fr/lbjlaq/Antigravity-Manager/faq/streaming-0token/index.md","filePath":"fr/lbjlaq/Antigravity-Manager/faq/streaming-0token/index.md"}`),n={name:"fr/lbjlaq/Antigravity-Manager/faq/streaming-0token/index.md"};function o(s,e,l,d,u,c){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="interruption-de-flux-0-token-signature-invalide-mecanisme-d-auto-guerison-et-chemin-de-depannage" tabindex="-1">Interruption de flux/0 Token/Signature invalide : mécanisme d&#39;auto-guérison et chemin de dépannage <a class="header-anchor" href="#interruption-de-flux-0-token-signature-invalide-mecanisme-d-auto-guerison-et-chemin-de-depannage" aria-label="Permalink to &quot;Interruption de flux/0 Token/Signature invalide : mécanisme d&#39;auto-guérison et chemin de dépannage&quot;">​</a></h1><p>Dans Antigravity Tools, lors de l&#39;appel de <code>/v1/messages</code> (compatible Anthropic) ou de l&#39;interface native de flux Gemini, si vous rencontrez des problèmes tels que « interruption de sortie de flux », « 200 OK mais 0 Token », « Invalid <code>signature</code> », cette leçon vous donne un chemin de dépannage de l&#39;UI aux journaux.</p><h2 id="ce-que-vous-saurez-faire-a-la-fin" tabindex="-1">Ce que vous saurez faire à la fin <a class="header-anchor" href="#ce-que-vous-saurez-faire-a-la-fin" aria-label="Permalink to &quot;Ce que vous saurez faire à la fin&quot;">​</a></h2><ul><li>Savoir que les problèmes 0 Token/interruption dans le proxy sont généralement bloqués en premier par « pré-lecture peek »</li><li>Pouvoir confirmer le compte et le modèle mappé de cette requête dans Proxy Monitor (<code>X-Account-Email</code> / <code>X-Mapped-Model</code>)</li><li>Pouvoir juger par les journaux si c&#39;est « flux en amont terminé tôt », « nouvelle tentative avec délai », « rotation de compte » ou « nouvelle tentative de réparation de signature »</li><li>Savoir dans quels cas attendre l&#39;auto-guérison du proxy, dans quels cas intervenir manuellement</li></ul><h2 id="votre-situation-actuelle" tabindex="-1">Votre situation actuelle <a class="header-anchor" href="#votre-situation-actuelle" aria-label="Permalink to &quot;Votre situation actuelle&quot;">​</a></h2><p>Vous pouvez voir ces « phénomènes », mais ne savez pas par où commencer :</p><ul><li>La sortie de flux s&#39;interrompt à moitié, le client semble « bloqué » et ne continue plus</li><li>200 OK, mais <code>usage.output_tokens=0</code> ou le contenu est vide</li><li>Erreur 400 contient <code>Invalid \\</code>signature`<code>, </code>Corrupted thought signature<code>, </code>must be `thinking`` etc.</li></ul><p>La plupart de ces problèmes ne sont pas « votre requête est mal écrite », mais plutôt transmission de flux, limitation/fluctuation en amont, ou blocs de signature portés dans les messages historiques déclenchent la validation en amont. Antigravity Tools a mis plusieurs lignes de défense dans la couche proxy, vous n&#39;avez qu&#39;à vérifier par un chemin fixe à quelle étape il bloque.</p><h2 id="qu-est-ce-que-0-token" tabindex="-1">Qu&#39;est-ce que 0 Token ? <a class="header-anchor" href="#qu-est-ce-que-0-token" aria-label="Permalink to &quot;Qu&#39;est-ce que 0 Token ?&quot;">​</a></h2><p><strong>0 Token</strong> signifie généralement <code>output_tokens=0</code> finalement renvoyé par une requête, et semble « n&#39;a généré aucun contenu ». Dans Antigravity Tools, sa cause la plus courante est « la réponse de flux se termine/se produit une erreur avant de vraiment sortir », plutôt que le modèle a vraiment généré 0 tokens. Le proxy essaiera d&#39;utiliser la pré-lecture peek pour bloquer ce type de réponse vide et déclencher une nouvelle tentative.</p><h2 id="trois-choses-que-le-proxy-fait-en-arriere-plan-d-abord-le-modele-mental" tabindex="-1">Trois choses que le proxy fait en arrière-plan (d&#39;abord le modèle mental) <a class="header-anchor" href="#trois-choses-que-le-proxy-fait-en-arriere-plan-d-abord-le-modele-mental" aria-label="Permalink to &quot;Trois choses que le proxy fait en arrière-plan (d&#39;abord le modèle mental)&quot;">​</a></h2><h3 id="_1-les-requetes-non-flux-peuvent-etre-automatiquement-converties-en-flux" tabindex="-1">1) Les requêtes non-flux peuvent être automatiquement converties en flux <a class="header-anchor" href="#_1-les-requetes-non-flux-peuvent-etre-automatiquement-converties-en-flux" aria-label="Permalink to &quot;1) Les requêtes non-flux peuvent être automatiquement converties en flux&quot;">​</a></h3><p>Dans le chemin <code>/v1/messages</code>, le proxy convertira en interne « la requête non-flux du client » en requête de flux pour demander l&#39;amont, puis collectera en JSON après avoir reçu SSE (la raison est indiquée dans le journal comme « better quota »).</p><p>Preuve du code source : <code>src-tauri/src/proxy/handlers/claude.rs#L665-L913</code>.</p><h3 id="_2-pre-lecture-peek-attendez-d-abord-«-le-premier-bloc-de-donnees-valides-»-avant-de-donner-le-flux-au-client" tabindex="-1">2) Pré-lecture peek : attendez d&#39;abord « le premier bloc de données valides » avant de donner le flux au client <a class="header-anchor" href="#_2-pre-lecture-peek-attendez-d-abord-«-le-premier-bloc-de-donnees-valides-»-avant-de-donner-le-flux-au-client" aria-label="Permalink to &quot;2) Pré-lecture peek : attendez d&#39;abord « le premier bloc de données valides » avant de donner le flux au client&quot;">​</a></h3><p>Pour la sortie SSE de <code>/v1/messages</code>, le proxy fera d&#39;abord <code>timeout + next()</code> pour pré-lecture, sautera les lignes de heartbeat/commentaire (commençant par <code>:</code>), jusqu&#39;à obtenir le premier bloc de données « non vide, non heartbeat » avant de commencer à transmettre formellement. Si peek échoue/expire/flux se termine, entrera directement dans la tentative suivante (la tentative suivante déclenchera généralement la rotation de compte).</p><p>Preuve du code source : <code>src-tauri/src/proxy/handlers/claude.rs#L812-L926</code> ; le flux natif Gemini a aussi peek similaire : <code>src-tauri/src/proxy/handlers/gemini.rs#L117-L149</code>.</p><h3 id="_3-nouvelle-tentative-avec-delai-unifie-decider-«-faut-il-faire-pivoter-le-compte-»-selon-le-code-d-etat" tabindex="-1">3) Nouvelle tentative avec délai unifié + décider « faut-il faire pivoter le compte » selon le code d&#39;état <a class="header-anchor" href="#_3-nouvelle-tentative-avec-delai-unifie-decider-«-faut-il-faire-pivoter-le-compte-»-selon-le-code-d-etat" aria-label="Permalink to &quot;3) Nouvelle tentative avec délai unifié + décider « faut-il faire pivoter le compte » selon le code d&#39;état&quot;">​</a></h3><p>Le proxy a une stratégie de délai claire pour les codes d&#39;état courants, et définit quels codes d&#39;état déclencheront la rotation de compte.</p><p>Preuve du code source : <code>src-tauri/src/proxy/handlers/claude.rs#L117-L236</code>.</p><h2 id="🎒-preparatifs-avant-de-commencer" tabindex="-1">🎒 Préparatifs avant de commencer <a class="header-anchor" href="#🎒-preparatifs-avant-de-commencer" aria-label="Permalink to &quot;🎒 Préparatifs avant de commencer&quot;">​</a></h2><ul><li>Vous pouvez ouvrir Proxy Monitor (voir <a href="./../../advanced/monitoring/">Proxy Monitor : journaux de requêtes, filtrage, restauration de détails et exportation</a>)</li><li>Vous savez que les journaux sont dans <code>logs/</code> du répertoire de données (voir <a href="./../../start/first-run-data/">Premier démarrage : répertoire de données, journaux, barre des tâches et démarrage automatique</a>)</li></ul><h2 id="suivez-moi" tabindex="-1">Suivez-moi <a class="header-anchor" href="#suivez-moi" aria-label="Permalink to &quot;Suivez-moi&quot;">​</a></h2><h3 id="etape-1-confirmer-quel-chemin-d-interface-vous-appelez" tabindex="-1">Étape 1 : Confirmer quel chemin d&#39;interface vous appelez <a class="header-anchor" href="#etape-1-confirmer-quel-chemin-d-interface-vous-appelez" aria-label="Permalink to &quot;Étape 1 : Confirmer quel chemin d&#39;interface vous appelez&quot;">​</a></h3><p><strong>Pourquoi</strong> Les détails d&#39;auto-guérison de <code>/v1/messages</code> (handler claude) et Gemini natif (handler gemini) sont différents, confirmez d&#39;abord le chemin pour éviter de perdre du temps sur de mauvais mots-clés de journal.</p><p>Ouvrez Proxy Monitor, trouvez cette requête échouée, notez d&#39;abord le Path :</p><ul><li><code>/v1/messages</code> : voir la logique de <code>src-tauri/src/proxy/handlers/claude.rs</code></li><li><code>/v1beta/models/...:streamGenerateContent</code> : voir la logique de <code>src-tauri/src/proxy/handlers/gemini.rs</code></li></ul><p><strong>Ce que vous devriez voir</strong> : dans l&#39;enregistrement de requête, vous pouvez voir URL/méthode/code d&#39;état (et durée de la requête).</p><h3 id="etape-2-capturer-«-compte-modele-mappe-»-dans-les-en-tetes-de-reponse" tabindex="-1">Étape 2 : Capturer « compte + modèle mappé » dans les en-têtes de réponse <a class="header-anchor" href="#etape-2-capturer-«-compte-modele-mappe-»-dans-les-en-tetes-de-reponse" aria-label="Permalink to &quot;Étape 2 : Capturer « compte + modèle mappé » dans les en-têtes de réponse&quot;">​</a></h3><p><strong>Pourquoi</strong> Qu&#39;une requête échoue/réussisse, beaucoup de choses dépendent de « quel compte a été sélectionné cette fois » « a été routé vers quel modèle amont ». Le proxy écrira ces deux informations dans les en-têtes de réponse, notez-les d&#39;abord, puis faites correspondre avec les journaux.</p><p>Dans cette requête échouée, cherchez ces en-têtes de réponse :</p><ul><li><code>X-Account-Email</code></li><li><code>X-Mapped-Model</code></li></ul><p>Ces deux éléments sont définis dans <code>/v1/messages</code> et le handler Gemini (par exemple, dans la réponse SSE <code>/v1/messages</code> : <code>src-tauri/src/proxy/handlers/claude.rs#L887-L896</code> ; Gemini SSE : <code>src-tauri/src/proxy/handlers/gemini.rs#L235-L245</code>).</p><p><strong>Ce que vous devriez voir</strong> : <code>X-Account-Email</code> est l&#39;e-mail, <code>X-Mapped-Model</code> est le nom de modèle réellement demandé.</p><h3 id="etape-3-dans-app-log-juger-si-«-echec-a-l-etape-peek-»" tabindex="-1">Étape 3 : Dans app.log, juger si « échec à l&#39;étape peek » <a class="header-anchor" href="#etape-3-dans-app-log-juger-si-«-echec-a-l-etape-peek-»" aria-label="Permalink to &quot;Étape 3 : Dans app.log, juger si « échec à l&#39;étape peek »&quot;">​</a></h3><p><strong>Pourquoi</strong> L&#39;échec peek signifie généralement « l&#39;amont n&#39;a même pas commencé à cracher des données valides ». Ce type de problème le plus souvent traité par nouvelle tentative/rotation de compte, vous devez confirmer si le proxy a déclenché.</p><p>D&#39;abord localisez le fichier journal (le répertoire de journaux vient de <code>logs/</code> du répertoire de données, écrit en rotation journalière dans <code>app.log*</code>).</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-lbiuK" id="tab-jLuGMSG" checked><label data-title="macOS/Linux" for="tab-jLuGMSG">macOS/Linux</label><input type="radio" name="group-lbiuK" id="tab-zsGiR3S"><label data-title="Windows" for="tab-zsGiR3S">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools/logs&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> head</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-ChildItem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Join-Path</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.antigravity_tools\\logs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Sort-Object</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> LastWriteTime </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Descending </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Select-Object</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">First </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span></span></code></pre></div></div></div><p>Ensuite, dans le dernier <code>app.log*</code>, cherchez ces mots-clés :</p><ul><li><code>/v1/messages</code> (handler claude) : <code>Stream error during peek</code> / <code>Stream ended during peek</code> / <code>Timeout waiting for first data</code> (<code>src-tauri/src/proxy/handlers/claude.rs#L828-L864</code>)</li><li>Flux natif Gemini : <code>[Gemini] Empty first chunk received, retrying...</code> / <code>Stream error during peek</code> / <code>Stream ended immediately</code> (<code>src-tauri/src/proxy/handlers/gemini.rs#L117-L144</code>)</li></ul><p><strong>Ce que vous devriez voir</strong> : si la nouvelle tentative peek est déclenchée, le journal affichera une alerte similaire à « retrying... », puis entrera dans la tentative suivante (généralement entraînera une rotation de compte).</p><h3 id="etape-4-si-400-signature-invalide-confirmer-si-le-proxy-a-fait-«-nouvelle-tentative-de-reparation-de-signature-»" tabindex="-1">Étape 4 : Si 400/Signature invalide, confirmer si le proxy a fait « nouvelle tentative de réparation de signature » <a class="header-anchor" href="#etape-4-si-400-signature-invalide-confirmer-si-le-proxy-a-fait-«-nouvelle-tentative-de-reparation-de-signature-»" aria-label="Permalink to &quot;Étape 4 : Si 400/Signature invalide, confirmer si le proxy a fait « nouvelle tentative de réparation de signature »&quot;">​</a></h3><p><strong>Pourquoi</strong> Les erreurs de signature proviennent souvent des blocs Thinking/blocs de signature dans les messages historiques qui ne répondent pas aux exigences de l&#39;amont. Antigravity Tools essaiera « rétrograder les blocs thinking historiques + injecter prompt de réparation » avant de réessayer, vous devriez d&#39;abord laisser l&#39;auto-guérison se terminer.</p><p>Vous pouvez juger s&#39;il est entré dans la logique de réparation avec 2 signaux :</p><ol><li>Le journal affiche <code>Unexpected thinking signature error ... Retrying with all thinking blocks removed.</code> (<code>src-tauri/src/proxy/handlers/claude.rs#L999-L1025</code>)</li><li>Ensuite convertira le bloc historique <code>Thinking</code> en <code>Text</code>, et ajoutera le prompt de réparation dans le dernier message utilisateur (<code>src-tauri/src/proxy/handlers/claude.rs#L1027-L1102</code> ; le handler Gemini ajoutera aussi le même prompt dans <code>contents[].parts</code> : <code>src-tauri/src/proxy/handlers/gemini.rs#L300-L325</code>)</li></ol><p><strong>Ce que vous devriez voir</strong> : le proxy réessaiera automatiquement après un court délai (<code>FixedDelay</code>), et peut entrer dans la tentative suivante.</p><h2 id="points-de-controle-✅" tabindex="-1">Points de contrôle ✅ <a class="header-anchor" href="#points-de-controle-✅" aria-label="Permalink to &quot;Points de contrôle ✅&quot;">​</a></h2><ul><li>[ ] Vous pouvez confirmer le chemin de requête dans Proxy Monitor (<code>/v1/messages</code> ou Gemini natif)</li><li>[ ] Vous pouvez obtenir <code>X-Account-Email</code> et <code>X-Mapped-Model</code> de cette requête</li><li>[ ] Vous pouvez rechercher les mots-clés peek/nouvelle tentative dans <code>logs/app.log*</code></li><li>[ ] En cas d&#39;erreur de signature 400, vous pouvez confirmer si le proxy est entré dans la logique de nouvelle tentative « réparation prompt + nettoyage blocs thinking »</li></ul><h2 id="attention-aux-pieges" tabindex="-1">Attention aux pièges <a class="header-anchor" href="#attention-aux-pieges" aria-label="Permalink to &quot;Attention aux pièges&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scénario</th><th>Ce que vous pourriez faire (❌)</th><th>Approche recommandée (✓)</th></tr></thead><tbody><tr><td>Voir 0 Token et immédiatement réessayer manuellement plusieurs fois</td><td>Continuer à appuyer sur le bouton de nouvelle tentative du client, sans regarder les journaux</td><td>D&#39;abord regarder une fois Proxy Monitor + app.log, confirmer si échec précoce à l&#39;étape peek (nouvelle tentative/rotation automatique)</td></tr><tr><td>Rencontre <code>Invalid \\</code>signature`` et videz directement le répertoire de données</td><td>Supprimez <code>.antigravity_tools</code> entier, comptes/statistiques tous perdus</td><td>Laissez d&#39;abord le proxy exécuter une « nouvelle tentative de réparation de signature » ; seulement quand le journal indique clairement irrécupérable, considérez l&#39;intervention manuelle</td></tr><tr><td>Confondre « fluctuation serveur » avec « compte cassé »</td><td>400/503/529一律 rotation de compte</td><td>La rotation est-elle efficace dépend du code d&#39;état ; le proxy a des règles <code>should_rotate_account(...)</code> (<code>src-tauri/src/proxy/handlers/claude.rs#L226-L236</code>)</td></tr></tbody></table><h2 id="resume-de-la-lecon" tabindex="-1">Résumé de la leçon <a class="header-anchor" href="#resume-de-la-lecon" aria-label="Permalink to &quot;Résumé de la leçon&quot;">​</a></h2><ul><li>0 Token/interruption de flux dans le passe généralement par la pré-lecture peek en premier ; l&#39;échec à l&#39;étape peek déclenchera une nouvelle tentative et entrera dans la tentative suivante</li><li><code>/v1/messages</code> peut convertir en interne les requêtes non-flux en flux puis collecter en JSON, cela affecte votre compréhension de « pourquoi cela ressemble à un problème de flux »</li><li>Pour les erreurs 400 de type signature invalide, le proxy essaiera « réparation prompt + nettoyage blocs thinking » avant de réessayer, vous devriez prioriser la vérification si ce chemin d&#39;auto-guérison fonctionne</li></ul><h2 id="prochaine-lecon" tabindex="-1">Prochaine leçon <a class="header-anchor" href="#prochaine-lecon" aria-label="Permalink to &quot;Prochaine leçon&quot;">​</a></h2><blockquote><p>La prochaine leçon, nous apprendrons <strong><a href="./../../appendix/endpoints/">Tableau de référence rapide des points de terminaison</a></strong>.</p></blockquote><hr><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : Référence du code source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : Référence du code source&quot;">​</a></h2><details><summary><strong>Cliquez pour voir l&#39;emplacement du code source</strong></summary><blockquote><p>Heure de mise à jour : 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Fonction</th><th>Chemin du fichier</th><th>Ligne</th></tr></thead><tbody><tr><td>Handler Claude : stratégie de nouvelle tentative avec délai + règles de rotation</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L117-L236" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>117-236</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Handler Claude : nouvelle tentative de réparation erreur 400 signature/ordre de blocs</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L999-L1102" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>999-1102</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Handler Gemini : injection de prompt de réparation erreur 400 signature</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/gemini.rs#L300-L325" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/gemini.rs</code></a></td><td>300-325</td></tr><tr><td>Cache de signature (trois couches : tool/family/session, incluant TTL/longueur minimale)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/signature_cache.rs#L5-L207" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/signature_cache.rs</code></a></td><td>5-207</td></tr><tr><td>Conversion SSE Claude : capture de signature et écriture dans cache de signature</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/mappers/claude/streaming.rs#L639-L787" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/mappers/claude/streaming.rs</code></a></td><td>639-787</td></tr></tbody></table><p><strong>Constantes clés</strong> :</p><ul><li><code>MAX_RETRY_ATTEMPTS = 3</code> : nombre maximum de nouvelles tentatives (<code>src-tauri/src/proxy/handlers/claude.rs#L27</code>)</li><li><code>SIGNATURE_TTL = 2 * 60 * 60</code> secondes : TTL cache de signature (<code>src-tauri/src/proxy/signature_cache.rs#L6</code>)</li><li><code>MIN_SIGNATURE_LENGTH = 50</code> : longueur minimale de signature (<code>src-tauri/src/proxy/signature_cache.rs#L7</code>)</li></ul><p><strong>Fonctions clés</strong> :</p><ul><li><code>determine_retry_strategy(...)</code> : sélectionner la stratégie de délai selon le code d&#39;état (<code>src-tauri/src/proxy/handlers/claude.rs#L117-L167</code>)</li><li><code>should_rotate_account(...)</code> : décider de faire pivoter le compte selon le code d&#39;état (<code>src-tauri/src/proxy/handlers/claude.rs#L226-L236</code>)</li><li><code>SignatureCache::cache_session_signature(...)</code> : mettre en cache la signature de session (<code>src-tauri/src/proxy/signature_cache.rs#L149-L188</code>)</li></ul></details>',57)])])}const h=a(n,[["render",o]]);export{m as __pageData,h as default};
